const AnimatedNumber: React.FC<{ target: number }> = ({ target }) => {
    const [current, setCurrent] = React.useState(0); const ref = React.useRef<HTMLSpanElement>(null);
    React.useEffect(() => {
        const observer = new IntersectionObserver(([entry]) => {
            if (entry.isIntersecting) {
                let startTimestamp: number | null = null;
                const step = (timestamp: number) => {
                    if (!startTimestamp) startTimestamp = timestamp;
                    const progress = Math.min((timestamp - startTimestamp) / 2000, 1);
                    setCurrent(Math.floor((1 - Math.pow(1 - progress, 4)) * target));
                    if (progress < 1) requestAnimationFrame(step); else setCurrent(target);
                }; requestAnimationFrame(step); observer.unobserve(entry.target);
            }}, { threshold: 0.5 });
        if (ref.current) observer.observe(ref.current); return () => { if (ref.current) observer.unobserve(ref.current) };
    }, [target]); return <span ref={ref}>{current.toLocaleString('id-ID')}</span>;
};

