import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Bell, SchedulesData } from '../types';
import { DAYS_OF_WEEK } from '../constants';

declare const Swal: any;

interface ScheduleEditorProps {
    schedules: SchedulesData;
    activeScheduleCategory: string;
    setActiveScheduleCategory: React.Dispatch<React.SetStateAction<string>>;
    scheduleCategories: string[];
    onUpdateBell: (category: string, day: string, bell: Bell) => void;
    onAddBell: (category: string, day: string, bell: Omit<Bell, 'id'>) => void;
    onDeleteBell: (category: string, day: string, bellId: string) => void;
    onCopySchedule: (fromDay: string, toDays: string[], category: string) => void;
    onAddCategory: (newCategoryName: string) => void;
    currentTime: Date;
    isAdmin: boolean;
}

const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve(reader.result as string);
        reader.onerror = error => reject(error);
    });
};

const BellRow: React.FC<{
    bell: Bell;
    onUpdate: (updatedBell: Bell) => void;
    onDelete: (bellId: string) => void;
    isAdmin: boolean;
}> = ({ bell, onUpdate, onDelete, isAdmin }) => {
    const [isEditing, setIsEditing] = useState(false);
    const [editState, setEditState] = useState(bell);
    const [isPlaying, setIsPlaying] = useState(false);
    const audioRef = useRef<HTMLAudioElement | null>(null);

    // Sync local state if the parent prop changes
    useEffect(() => {
        setEditState(bell);
    }, [bell]);

    // Cleanup audio on component unmount
    useEffect(() => {
        return () => {
            if (audioRef.current) {
                audioRef.current.pause();
                audioRef.current = null;
            }
        };
    }, []);

    const handleStopSound = () => {
        if (audioRef.current) {
            audioRef.current.pause();
            audioRef.current.currentTime = 0;
            audioRef.current = null;
        }
        setIsPlaying(false);
    };

    const handlePlaySound = () => {
        if (!bell.sound) return;

        // If something is already playing, this function effectively acts as a "restart"
        if (audioRef.current) {
            handleStopSound();
        }

        const audio = new Audio(bell.sound);
        audioRef.current = audio;
        setIsPlaying(true);

        audio.onended = () => {
            setIsPlaying(false);
            audioRef.current = null;
        };

        audio.onerror = (e) => {
            console.error("Playback error:", e);
            setIsPlaying(false);
            audioRef.current = null;
            Swal.fire({title: 'Gagal', text: 'Gagal memutar file audio. File mungkin rusak.', icon: 'error', confirmButtonColor: '#dc2626'});
        };

        audio.play().catch(e => {
            console.error("Error initiating playback:", e);
            setIsPlaying(false);
            audioRef.current = null;
            Swal.fire({title: 'Gagal', text: 'Gagal memulai pemutaran audio.', icon: 'error', confirmButtonColor: '#dc2626'});
        });
    };

    const handleSave = () => {
        onUpdate(editState);
        setIsEditing(false);
    };

    const confirmDelete = () => {
        Swal.fire({
            title: 'Anda yakin?',
            text: `Anda akan menghapus bel "${bell.name}".`,
            icon: 'warning',
            showCancelButton: true,
            confirmButtonColor: '#d33',
            cancelButtonColor: '#6b7280',
            confirmButtonText: 'Ya, hapus!',
            cancelButtonText: 'Batal'
        }).then((result: { isConfirmed: boolean }) => {
            if (result.isConfirmed) {
                onDelete(bell.id);
                Swal.fire({title: 'Dihapus!', text: 'Jadwal bel telah dihapus.', icon: 'success', confirmButtonColor: '#dc2626'});
            }
        });
    };

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            if (file.size > 2 * 1024 * 1024) { // 2MB limit
                Swal.fire({title: 'Gagal', text: 'Ukuran file tidak boleh melebihi 2MB.', icon: 'error', confirmButtonColor: '#dc2626'});
                e.target.value = ''; // Reset file input
                return;
            }
            try {
                const base64 = await fileToBase64(file);
                setEditState({ ...editState, sound: base64, soundName: file.name });
            } catch (error) {
                console.error("Error converting file to base64", error);
                Swal.fire({title: 'Gagal', text: 'Gagal memproses file audio.', icon: 'error', confirmButtonColor: '#dc2626'});
            }
        }
    };

    if (isEditing) {
        return (
            <div className="flex flex-col sm:grid sm:grid-cols-12 gap-3 items-center p-3 bg-red-50 rounded-lg border border-red-200">
                 <div className="relative w-full sm:col-span-4">
                    <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                        <i className="fa-solid fa-bell text-slate-400"></i>
                    </div>
                    <input type="text" value={editState.name} onChange={e => setEditState({...editState, name: e.target.value})} className="form-input pl-10" placeholder="Nama Bel"/>
                </div>
                 <div className="relative w-full sm:col-span-3">
                    <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                       <i className="fa-solid fa-clock text-slate-400"></i>
                    </div>
                    <input type="time" value={editState.time} onChange={e => setEditState({...editState, time: e.target.value})} className="form-input pl-9" />
                </div>
                <div className="w-full sm:col-span-3">
                    <label htmlFor={`sound-upload-${bell.id}`} className="w-full text-center px-3 py-2 bg-white border border-slate-300 rounded-lg text-sm font-medium text-slate-700 hover:bg-slate-50 transition-colors cursor-pointer truncate flex items-center justify-center space-x-2 shadow-sm">
                         <i className="fa-solid fa-arrow-up-from-bracket text-slate-400"></i>
                        <span className="truncate">{editState.soundName || 'Suara'}</span>
                    </label>
                    <input id={`sound-upload-${bell.id}`} type="file" onChange={handleFileChange} accept=".mp3,.wav,.ogg" className="sr-only"/>
                </div>
                <div className="flex items-center space-x-2 sm:col-span-2 justify-end w-full sm:w-auto">
                    <button onClick={handleSave} className="flex-1 sm:flex-none p-2 w-full sm:w-10 h-10 flex items-center justify-center bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors shadow-sm">
                        <i className="fa-solid fa-check"></i>
                    </button>
                    <button onClick={() => setIsEditing(false)} className="flex-1 sm:flex-none p-2 w-full sm:w-10 h-10 flex items-center justify-center bg-slate-400 text-white rounded-lg hover:bg-slate-500 transition-colors shadow-sm">
                        <i className="fa-solid fa-xmark"></i>
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className={`grid ${isAdmin ? 'grid-cols-[2fr_0.8fr_1.5fr_0.5fr_1fr]' : 'grid-cols-[2fr_0.8fr_1.5fr_0.5fr]'} gap-4 items-center px-3 py-2 border-b border-slate-100 last:border-b-0 hover:bg-slate-100/70 rounded-lg`}>
            <span className="font-medium text-slate-800 truncate">{bell.name}</span>
            <span className="font-mono text-slate-600 text-sm">{bell.time}</span>
            <span className="text-slate-500 text-sm truncate min-w-0">{bell.soundName || <span className="text-slate-400 italic text-xs">Hening</span>}</span>
            <div className="flex justify-center">
                {bell.sound && (
                     <button 
                        onClick={isPlaying ? handleStopSound : handlePlaySound}
                        className={`p-2 w-8 h-8 flex items-center justify-center rounded-full transition group focus:outline-none focus:ring-2 focus:ring-offset-2
                            ${isPlaying 
                                ? 'bg-red-500 text-white hover:bg-red-600 focus:ring-red-500 shadow-sm' 
                                : 'bg-slate-200 text-slate-600 hover:bg-red-100 hover:text-red-600 focus:ring-red-500'
                            }`}
                        aria-label={isPlaying ? "Hentikan suara" : "Putar suara"}
                    >
                        {isPlaying ? (
                             <i className="fa-solid fa-stop text-xs"></i>
                        ) : (
                            <i className="fa-solid fa-play text-xs"></i>
                        )}
                    </button>
                )}
            </div>
            {isAdmin && (
                <div className="flex items-center space-x-1 justify-end">
                    <button onClick={() => setIsEditing(true)} className="p-2 text-slate-400 hover:text-slate-700 hover:bg-slate-200 rounded-full transition-colors" aria-label="Ubah Bel">
                        <i className="fa-solid fa-pencil h-4 w-4"></i>
                    </button>
                    <button onClick={confirmDelete} className="p-2 text-red-400 hover:text-red-700 hover:bg-red-100 rounded-full transition-colors" aria-label="Hapus Bel">
                        <i className="fa-solid fa-trash-can h-4 w-4"></i>
                    </button>
                </div>
            )}
        </div>
    );
};

const BellTable: React.FC<{
    bells: Bell[];
    onUpdate: (updatedBell: Bell) => void;
    onDelete: (bellId: string) => void;
    isAdmin: boolean;
}> = ({ bells, onUpdate, onDelete, isAdmin }) => (
    <div className="space-y-1">
        <div className={`grid ${isAdmin ? 'grid-cols-[2fr_0.8fr_1.5fr_0.5fr_1fr]' : 'grid-cols-[2fr_0.8fr_1.5fr_0.5fr]'} gap-4 px-3 py-2 bg-red-50 rounded-t-lg border-b border-red-100`}>
            <span className="text-[10px] font-bold text-red-700 uppercase tracking-wider">Nama</span>
            <span className="text-[10px] font-bold text-red-700 uppercase tracking-wider">Waktu</span>
            <span className="text-[10px] font-bold text-red-700 uppercase tracking-wider">Suara</span>
            <span className="text-[10px] font-bold text-red-700 uppercase tracking-wider text-center">Cek</span>
            {isAdmin && <span className="text-[10px] font-bold text-red-700 uppercase tracking-wider text-right">Aksi</span>}
        </div>
        {bells.map(bell => (
            <BellRow
                key={bell.id}
                bell={bell}
                onUpdate={onUpdate}
                onDelete={onDelete}
                isAdmin={isAdmin}
            />
        ))}
    </div>
);

export const ScheduleEditor: React.FC<ScheduleEditorProps> = ({
    schedules,
    activeScheduleCategory,
    setActiveScheduleCategory,
    scheduleCategories,
    onUpdateBell,
    onAddBell,
