    onAddCategory,
    currentTime,
    isAdmin,
}) => {
    const todayIndex = (currentTime.getDay() + 6) % 7;
    const [selectedDay, setSelectedDay] = useState(DAYS_OF_WEEK[todayIndex]);

    const [newBellName, setNewBellName] = useState('');
    const [newBellTime, setNewBellTime] = useState('07:00');
