    const [newBellSoundName, setNewBellSoundName] = useState('');
    const fileInputRef = useRef<HTMLInputElement>(null);

    const activeSchedule = schedules[activeScheduleCategory]?.[selectedDay] || [];

    useEffect(() => {
        setSelectedDay(DAYS_OF_WEEK[todayIndex]);
    }, [activeScheduleCategory, todayIndex]);

    const handleNewFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
             if (file.size > 2 * 1024 * 1024) { // 2MB limit
                Swal.fire({title: 'Gagal', text: 'Ukuran file tidak boleh melebihi 2MB.', icon: 'error', confirmButtonColor: '#dc2626'});
                e.target.value = ''; // Reset file input
                return;
            }
            try {
                const base64 = await fileToBase64(file);
                setNewBellSound(base64);
                setNewBellSoundName(file.name);
            } catch (error) {
                console.error("Error converting file to base64", error);
                Swal.fire({title: 'Gagal', text: 'Gagal memproses file audio.', icon: 'error', confirmButtonColor: '#dc2626'});
            }
        }
    };

    const handleAddBellSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!newBellName.trim() || !newBellTime) {
            Swal.fire({title: 'Gagal', text: 'Nama bel dan waktu tidak boleh kosong.', icon: 'warning', confirmButtonColor: '#dc2626'});
            return;
        }
        onAddBell(activeScheduleCategory, selectedDay, {
            name: newBellName,
            time: newBellTime,
            sound: newBellSound,
            soundName: newBellSoundName || 'Tidak ada suara',
        });
        // Reset form
        setNewBellName('');
        setNewBellTime('07:00');
        setNewBellSound('');
        setNewBellSoundName('');
        if(fileInputRef.current) fileInputRef.current.value = '';
    };

    const showAddCategoryModal = () => {
        Swal.fire({
            title: 'Tambah Kategori Jadwal Baru',
            input: 'text',
