                <p class="text-slate-600 text-sm mb-4">Pilih hari tujuan untuk menyalin jadwal. Jadwal yang ada pada hari tujuan akan ditimpa.</p>
                <div id="swal-checkbox-container" class="grid grid-cols-2 sm:grid-cols-3 gap-2 text-left">
                    ${daysToCopyTo.map(day => `
                        <label for="swal-checkbox-${day}" class="flex items-center space-x-2 p-2 rounded-lg hover:bg-slate-100 cursor-pointer">
                            <input type="checkbox" id="swal-checkbox-${day}" value="${day}" class="h-4 w-4 rounded border-gray-300 text-red-600 focus:ring-red-500">
                            <span>${day}</span>
                        </label>
                    `).join('')}
                </div>
            `,
            showCancelButton: true,
            confirmButtonText: 'Salin',
            cancelButtonText: 'Batal',
            confirmButtonColor: '#dc2626',
            didOpen: () => {
                const container = document.getElementById('swal-checkbox-container');
                if(container){
                    container.addEventListener('change', (e) => {
                        const target = e.target as HTMLInputElement;
                        if(target.type === 'checkbox') {
                            if (target.checked) {
