                            } else {
                                selectedCheckboxes = selectedCheckboxes.filter(v => v !== target.value);
                            }
                        }
                    });
                }
            },
            preConfirm: () => {
                if (selectedCheckboxes.length === 0) {
                    Swal.showValidationMessage('Anda harus memilih setidaknya satu hari tujuan.');
                    return false;
                }
                return selectedCheckboxes;
            }
        }).then((result: {value: string[]}) => {
