            }
            try {
                const base64 = await fileToBase64(file);
                setEditState({ ...editState, sound: base64, soundName: file.name });
            } catch (error) {
                Swal.fire({ title: 'Gagal', text: 'Gagal memproses file audio.', icon: 'error', confirmButtonColor: '#dc2626' });
