                                `}
                            >
                                {day}
                            </button>
                        ))}
                    </nav>
                </div>

                <div className="bg-slate-50/30 rounded-xl border border-slate-100 p-2 sm:p-4">
                    {isAdmin && activeSchedule.length > 0 && (
                        <div className="flex justify-end mb-2">
